const CATEGORIES = [
  'all',
  'frontend',
  'backendData',
  'platforms',
  'tools',
] as const;

const Work: React.FC<WorkProps> = ({ setDialogText, setCurrentAction, lang }) => {
  const t = getTranslations(lang);
  const [activeCategory, setActiveCategory] = useState('all');

  const categoryDescriptions = useMemo(
    () => ({
      all: t.work.categoryDescriptions.all,
      frontend: t.work.categoryDescriptions.frontend,
      backendData: t.work.categoryDescriptions.backendData,
      platforms: t.work.categoryDescriptions.platforms,
      tools: t.work.categoryDescriptions.tools,
    }),
    [t]
  );

  const filteredTech = useMemo(
    () =>
      activeCategory === 'all'
        ? TECH_DATA
        : TECH_DATA.filter((tech) => tech.category === activeCategory),
    [activeCategory]
  );

  const handleCategoryClick = useCallback((category: string) => {
    setActiveCategory(category);
  }, []);

  const handleViewProjects = useCallback(() => {
    setCurrentAction?.('goTo-portfolio');
    setDialogText?.(t.work.showTechnologies);
  }, [setCurrentAction, setDialogText, t.work.showTechnologies]);

  return (
    <div id="work" className="retro-page">
      <PageNavigation currentSection="goTo-work" onNavigate={setCurrentAction} lang={lang} />

      <div className="page-content">
        <h1 className="work-title">{t.work.title}</h1>

        <div className="work-description-box retro-box" style={{ marginBottom: '20px' }}>
          <p>{categoryDescriptions[activeCategory]}</p>
        </div>
        {/* Category Tabs */}
        <div className="work-category-tabs category-tabs">
          {CATEGORIES.map((cat) => (
            <div
              key={cat}
              className={`category-tab ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => handleCategoryClick(cat)}
            >
              {t.work.categories[cat]}
            </div>
          ))}
        </div>

        <div className="work-tech-stack stack">
          {filteredTech.map((tech, index) => (
            <div key={index} className="work-tech-item tech-item">
              <img src={tech.img} alt={tech.name} title={tech.name} />
              <div style={{ fontSize: '10px', fontWeight: 'bold', marginBottom: '5px' }}>
                {tech.name}
              </div>
            </div>
          ))}
        </div>

        <div className="content-section" style={{ marginTop: '30px' }}>
          <div style={{ textAlign: 'center' }}>
            <button className="retro-button primary" onClick={handleViewProjects}>
              💼 {t.work.viewProjects}
            </button>
            <p>
              {t.work.followOnGithub}&nbsp;
              <a
                href="https://github.com/mawmawmaw/"
                target="_blank"
                rel="noreferrer"
                style={{ color: '#0066cc', textDecoration: 'underline' }}
              >
                GitHub
              </a>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Work;
